import "./dialog.css";

import { Dialog } from "radix-ui";

import { DialogContext } from "./dialog.context";
import { dialogVariants } from "./dialog.variants";

export type DialogRootProps = React.ComponentProps<typeof Dialog.Root>;

export const DialogRoot = (props: DialogRootProps) => {
  const slots = dialogVariants();

  return (
    <DialogContext value={{ slots }}>
      <Dialog.Root {...props} />
    </DialogContext>
  );
};

import { Dialog } from "radix-ui";

export type DialogTriggerProps = React.ComponentProps<typeof Dialog.Trigger>;

export const DialogTrigger = (props: DialogTriggerProps) => {
  return <Dialog.Trigger asChild {...props} />;
};

import { X } from "lucide-react";
import { Dialog } from "radix-ui";
import { cn } from "tailwind-variants";

import { useDialogContext } from "./dialog.context";

export type DialogContentProps = React.ComponentProps<typeof Dialog.Content>;

export const DialogContent = ({ children, className, ...props }: DialogContentProps) => {
  const { slots } = useDialogContext();

  return (
    <Dialog.Portal>
      <Dialog.Overlay className={slots.overlay()} />
      <Dialog.Content className={cn(slots.content(), className)} {...props}>
        {children}
        <Dialog.Close className={slots.close()}>
          <X />
          <span className="sr-only">Close</span>
        </Dialog.Close>
      </Dialog.Content>
    </Dialog.Portal>
  );
};

import { Dialog } from "radix-ui";
import { cn } from "tailwind-variants";

import { useDialogContext } from "./dialog.context";

export type DialogTitleProps = React.ComponentProps<typeof Dialog.Title>;

export const DialogTitle = ({ className, ...props }: DialogTitleProps) => {
  const { slots } = useDialogContext();

  return <Dialog.Title className={cn(slots.title(), className)} {...props} />;
};

import { Dialog } from "radix-ui";
import { cn } from "tailwind-variants";

import { useDialogContext } from "./dialog.context";

export type DialogDescriptionProps = React.ComponentProps<typeof Dialog.Description>;

export const DialogDescription = ({ className, ...props }: DialogDescriptionProps) => {
  const { slots } = useDialogContext();

  return <Dialog.Description className={cn(slots.description(), className)} {...props} />;
};

import { cn } from "tailwind-variants";

import { useDialogContext } from "./dialog.context";

export type DialogFooterProps = React.ComponentProps<"div">;

export const DialogFooter = ({ className, ...props }: DialogFooterProps) => {
  const { slots } = useDialogContext();

  return <div className={cn(slots.footer(), className)} {...props} />;
};

import { createContext, useContext } from "react";

import { dialogVariants } from "./dialog.variants";

export type DialogContext = {
  slots: ReturnType<typeof dialogVariants>;
};

export const DialogContext = createContext<DialogContext | null>(null);

export const useDialogContext = () => {
  const context = useContext(DialogContext);
  if (!context) {
    throw new Error("useDialogContext must be used within a Dialog");
  }
  return context;
};

import { tv, type VariantProps } from "tailwind-variants";

export const dialogVariants = tv({
  slots: {
    close: "dialog__close",
    content: "dialog__content",
    description: "dialog__description",
    footer: "dialog__footer",
    overlay: "dialog__overlay",
    title: "dialog__title",
  },
});

export type DialogVariants = VariantProps<typeof dialogVariants>;

.dialog__overlay {
  @apply fixed inset-0 z-50 bg-black/80;

  &[data-state="open"] {
    @apply animate-in fade-in-0;
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0;
  }
}

.dialog__content {
  @apply bg-background fixed top-1/2 left-1/2 z-50 grid w-full max-w-lg -translate-x-1/2 -translate-y-1/2 gap-4 rounded-lg border p-6 shadow-lg duration-200;

  &[data-state="open"] {
    @apply animate-in fade-in-0 zoom-in-95 slide-in-from-left-1/2 slide-in-from-top-[48%];
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0 zoom-out-95 slide-out-to-left-1/2 slide-out-to-top-[48%];
  }
}

.dialog__title {
  @apply text-lg leading-none font-semibold tracking-tight;
}

.dialog__description {
  @apply text-muted-foreground text-sm;
}

.dialog__footer {
  @apply flex flex-col-reverse gap-2 sm:flex-row sm:justify-end;
}

.dialog__close {
  @apply absolute top-4 right-4 rounded-sm opacity-70 transition-opacity;

  &:hover {
    @apply opacity-100;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  & svg {
    @apply size-4;
  }
}

import { DialogContent } from "./dialog-content";
import { DialogDescription } from "./dialog-description";
import { DialogFooter } from "./dialog-footer";
import { DialogRoot } from "./dialog-root";
import { DialogTitle } from "./dialog-title";
import { DialogTrigger } from "./dialog-trigger";

export const Dialog = {
  Content: DialogContent,
  Description: DialogDescription,
  Footer: DialogFooter,
  Root: DialogRoot,
  Title: DialogTitle,
  Trigger: DialogTrigger,
};

export { DialogContent, DialogDescription, DialogFooter, DialogRoot, DialogTitle, DialogTrigger };

export { DialogContext, useDialogContext } from "./dialog.context";

export { type DialogVariants, dialogVariants } from "./dialog.variants";
